const items = $input.all().map(i => i.json);

let cards = [], backCommits = [], frontCommits = [], prevSnapshot = {};

for (const it of items) {
  if (Array.isArray(it) && it[0]?.id?.length === 24 && 'dueComplete' in it[0]) {
    cards = it;
  } else if (Array.isArray(it) && it[0]?.sha && it[0]?.commit) {
    // Distinguish back vs front by url
    const url = it[0].url || '';
    if (url.includes($node['Configuración'].json.GITHUB_REPO_BACKEND)) backCommits = it;
    else if (url.includes($node['Configuración'].json.GITHUB_REPO_FRONTEND)) frontCommits = it;
  } else if (it.snapshot) {
    prevSnapshot = typeof it.snapshot === 'string' ? JSON.parse(it.snapshot) : it.snapshot;
  }
}

const prev = {
  main_commit_back_sha: prevSnapshot.main_commit_back_sha || null,
  main_commit_front_sha: prevSnapshot.main_commit_front_sha || null,
  card_states: prevSnapshot.card_states || {}
};

const events = [];
const newCardStates = {};

for (const c of cards) {
  const attCount = (c.attachments || []).length;
  const pdfAtts = (c.attachments || []).filter(a => (a.mimeType || '').includes('pdf') || (a.name || '').toLowerCase().endsWith('.pdf'));
  newCardStates[c.id] = {
    dueComplete: !!c.dueComplete,
    attCount,
    pdfCount: pdfAtts.length
  };
  const prevCard = prev.card_states[c.id];
  if (prevCard) {
    if (!prevCard.dueComplete && c.dueComplete) {
      events.push({
        tipo: 'tarea_completada',
        emoji: '✅',
        titulo: 'Tarea completada',
        descripcion: `La tarjeta "${c.name}" fue marcada como completada.`,
        detalle: { card_id: c.id, card_name: c.name, due: c.due }
      });
    }
    if ((prevCard.pdfCount || 0) < pdfAtts.length) {
      const newPdfs = pdfAtts.slice(-(pdfAtts.length - (prevCard.pdfCount || 0)));
      events.push({
        tipo: 'entregable_subido',
        emoji: '📎',
        titulo: 'Nuevo entregable PDF',
        descripcion: `Se subió un PDF a "${c.name}": ${newPdfs.map(p => p.name).join(', ')}`,
        detalle: { card_id: c.id, card_name: c.name, pdfs: newPdfs.map(p => ({ name: p.name, url: p.url })) }
      });
    }
  }
}

const latestBack = backCommits[0];
if (latestBack && latestBack.sha !== prev.main_commit_back_sha) {
  if (prev.main_commit_back_sha) {
    events.push({
      tipo: 'commit_main_backend',
      emoji: '🔀',
      titulo: 'Commit a main (backend)',
      descripcion: `${latestBack.commit?.author?.name || '?'}: ${(latestBack.commit?.message || '').split('\n')[0]}`,
      detalle: { repo: 'backend', sha: latestBack.sha, url: latestBack.html_url, autor: latestBack.commit?.author?.name, mensaje: latestBack.commit?.message }
    });
  }
}

const latestFront = frontCommits[0];
if (latestFront && latestFront.sha !== prev.main_commit_front_sha) {
  if (prev.main_commit_front_sha) {
    events.push({
      tipo: 'commit_main_frontend',
      emoji: '🔀',
      titulo: 'Commit a main (frontend)',
      descripcion: `${latestFront.commit?.author?.name || '?'}: ${(latestFront.commit?.message || '').split('\n')[0]}`,
      detalle: { repo: 'frontend', sha: latestFront.sha, url: latestFront.html_url, autor: latestFront.commit?.author?.name, mensaje: latestFront.commit?.message }
    });
  }
}

const newSnapshot = {
  main_commit_back_sha: latestBack?.sha || prev.main_commit_back_sha,
  main_commit_front_sha: latestFront?.sha || prev.main_commit_front_sha,
  card_states: newCardStates
};

return [{
  json: {
    events,
    event_count: events.length,
    new_snapshot: newSnapshot,
    new_snapshot_json: JSON.stringify(newSnapshot)
  }
}];

