const ev = $node['Split Events'].json;
const gem = $json;
const analysis = gem?.candidates?.[0]?.content?.parts?.[0]?.text?.trim() || '';

let extra = '';
if (ev.detalle?.url) extra = `\n🔗 ${ev.detalle.url}`;
if (ev.detalle?.pdfs?.length) extra = '\n' + ev.detalle.pdfs.map(p => `📄 [${p.name}](${p.url})`).join('\n');

const content = `${ev.emoji} **${ev.titulo}**\n${ev.descripcion}${extra}\n\n🤖 ${analysis}`;

return [{ json: {
  ...ev,
  analysis,
  content,
  detalle_json: JSON.stringify(ev.detalle || {})
}}];
